            ArgumentNullException.ThrowIfNull(msg2.DataBlock);

            Assert.That(msg2.DataBlock.Data.Length, Is.EqualTo(msg.Length - 8));

            var db = (SfxpInboundDatablock)msg2.DataBlock;
            Assert.That(db.DataChunks.Count, Is.Not.Zero);
            Assert.That(db.DataChunks.Any(x => x.Channel > 0), Is.True);

            var chunk = db.DataChunks[0];
            ArgumentNullException.ThrowIfNull(chunk.Data);

            var data = chunk.Data.Value;
            var testValue = data[..1].Span[0];
            Assert.That(data.Slice(1, 1).Span[0], Is.EqualTo(testValue));
            Assert.That(data.Slice(7, 1).Span[0], Is.EqualTo(testValue));
        }
