        var index = 0;
        for (index = 8; index < data.Length; index++)
        {
            var b = data.Span[index];

            if (b == 0xed && data.Span[index + 1] == 0x0 && data.Span[index + 2] == 0x0 && data.Span[index + 3] == 0x0 && data.Span[index + 4] == 0x0 && data.Span[index + 5] == 0x0 && data.Span[index + 6] == 0x0 && data.Span[index + 7] == 0x0)
