        var result2 = result.ToArray();
        Debug.Print(ArrayHelper.GetStringFromArrayCsharpStyle(result, false));

        var messageId = BitConverter.ToUInt64(result.AsMemory().Slice(0, 8).Span);
        Debug.Print(messageId.ToString());

