    private void CheckResult(InboundCodecResult? result, bool hasChunks = true)
    {
        using (Assert.EnterMultipleScope())
        {
            Assert.That(result, Is.Not.Null);
            ArgumentNullException.ThrowIfNull(result);
            Assert.That(result.ErrorCode, Is.Zero);

            Assert.That(result.DataMessage, Is.Not.Null);
            ArgumentNullException.ThrowIfNull(result.DataMessage);
            Assert.That(result.DataMessage.RawMessageData.Length, Is.Not.Zero);

            var msg2 = (SfxpInboundDataMessage)result.DataMessage;

            Assert.That(msg2, Is.Not.Null);
            ArgumentNullException.ThrowIfNull(msg2.DataBlock);

            var db = (SfxpInboundDatablock)msg2.DataBlock;

            if (hasChunks)
            {
                Assert.That(db.DataChunks.Count, Is.Not.Zero);

                Assert.That(db.DataChunks.Any(x => x.Channel == 0), Is.True);
                //Assert.That(db.DataChunks.Any(x => x is { Channel: 0xc, DataChunkType: DataChunkType.SampleCounterSyncChunk }), Is.True);
                Assert.That(db.DataChunks.Any(x => x.Channel == 255), Is.False);

                // 
                foreach (var chunk in db.DataChunks.Where(x => x.Channel == 0xc))
                {
                    CheckForSampleChunk(chunk);
                }

                // Return chunks to pool
                foreach (var chunk in db.DataChunks)
                {
                    chunk.ReturnDataChunkDelegate?.Invoke(chunk);
                }
                db.DataChunks.Clear();
            }
            else
            {
                Assert.That(db.DataChunks.Count, Is.Zero);
            }
        }

    }

    private static void WriteToFile(int index, byte[] message)
    {
        var filePath = $"C:\\temp\\sfx{index}RealWorld.bin";

        Debug.Print($"Length: {message.Length}B");

        File.WriteAllBytes(filePath, message);
    }

    private static void CheckForSampleChunk(DataChunk chunk)
    {
        var data = chunk.Data!.Value;

        if (data.Span[7] != 0x9)
        {
            Debug.Print($"Wrong chunk {ArrayHelper.GetStringFromArrayCsharpStyle(data, false)}");
        }

        if (data.Span[5] != 0x9)
        {
            Debug.Print($"Wrong chunk {ArrayHelper.GetStringFromArrayCsharpStyle(data, false)}");
        }

        if (data.Span[3] != 0x9)
        {
            Debug.Print($"Wrong chunk {ArrayHelper.GetStringFromArrayCsharpStyle(data, false)}");
        }

        if (data.Span[1] != 0x9)
        {
            Debug.Print($"Wrong chunk {ArrayHelper.GetStringFromArrayCsharpStyle(data, false)}");
        }
    }
}